Принудительная коррекция
Некоторые обновления нельзя откладывать независимо от их обычной оценки:
Первое условие означает, что данные стали слишком старыми.
Второе означает, что система больше не доверяет локальной коррекции. Например, после резкого движения камеры в старом кадре могут открыться области, для которых вообще нет корректного изображения.
В таком случае система может:
немедленно запросить свежий тайл;
временно снизить качество соседних областей;
отправить небольшой аварийный патч;
заменить участок упрощённым изображением;
отключить локальную деформацию для проблемной зоны.
Принудительные обновления должны резервировать ресурсы раньше обычной очереди.
Упрощённый планировщик на Rust
Ниже приведён пример, который:
вычисляет приоритет каждого тайла;
определяет допустимый возраст;
вычисляет запас времени и оценку;
сначала выбирает обязательные исправления;
затем добавляет остальные тайлы по убыванию оценки;
учитывает ограничения сети, декодера и композиции.
use std::cmp::Ordering;

#[derive(Clone, Copy)]
struct Factors {
 attention: f64,
 motion: f64,
 input: f64,
 target: f64,
 saliency: f64,
 interface: f64,
}

#[derive(Clone, Copy)]
struct Weights {
 attention: f64,
 motion: f64,
 input: f64,
 target: f64,
 saliency: f64,
 interface: f64,
}

#[derive(Clone)]
struct Tile {
 name: &'static str,
 factors: Factors,

 // Уверенность в текущем локальном изображении.
 confidence: f64,

 // Текущий возраст данных в миллисекундах.
 age_ms: f64,

 // Ожидаемое уменьшение визуальной ошибки.
 delta_error: f64,

 // Стоимость передачи и обработки.
 bytes_kb: f64,
 decode_cost: f64,
 compose_ms: f64,
}

#[derive(Clone, Copy)]
struct Config {
 min_age_ms: f64,
 max_age_ms: f64,
 gamma: f64,
 epsilon: f64,
 critical_confidence: f64,
}

#[derive(Debug)]
struct EvaluatedTile {
 index: usize,
 priority: f64,
 age_limit_ms: f64,
 slack_ms: f64,
 score: f64,
 forced: bool,
}

fn calculate_priority(tile: &Tile, weights: Weights) -> f64 {
 let f = tile.factors;

 let priority =
 weights.attention * f.attention
 + weights.motion * f.motion
 + weights.input * f.input
 + weights.target * f.target
 + weights.saliency * f.saliency
 + weights.interface * f.interface;

 priority.clamp(0.0, 1.0)
}

fn calculate_age_limit(
 priority: f64,
 confidence: f64,
 config: Config,
) -> f64 {
 let extra_age =
 (config.max_age_ms - config.min_age_ms)
 * (1.0 - priority).powf(config.gamma)
 * confidence.clamp(0.0, 1.0);

 config.min_age_ms + extra_age
}

fn evaluate_tile(
 index: usize,
 tile: &Tile,
 weights: Weights,
 config: Config,
) -> EvaluatedTile {
 let priority = calculate_priority(tile, weights);

 let age_limit_ms =
 calculate_age_limit(priority, tile.confidence, config);

 let slack_ms = age_limit_ms - tile.age_ms;

 let denominator =
 tile.bytes_kb
 * (config.epsilon + slack_ms.max(0.0));

 let score = if denominator > 0.0 {
 priority * tile.delta_error / denominator
 } else {
 f64::INFINITY
 };

 let forced =
 tile.age_ms > age_limit_ms
 || tile.confidence < config.critical_confidence;

 EvaluatedTile {
 index,
 priority,
 age_limit_ms,
 slack_ms,
 score,
 forced,
 }
}

fn try_reserve(
 tile: &Tile,
 network_left: &mut f64,
 decode_left: &mut f64,
 compose_left: &mut f64,
) -> bool {
 let fits =
 tile.bytes_kb <= *network_left
 && tile.decode_cost <= *decode_left
 && tile.compose_ms <= *compose_left;

 if !fits {
 return false;
 }

 *network_left -= tile.bytes_kb;
 *decode_left -= tile.decode_cost;
 *compose_left -= tile.compose_ms;

 true
}

fn main() {
 let weights = Weights {
 attention: 0.35,
 motion: 0.20,
 input: 0.15,
 target: 0.20,
 saliency: 0.10,
 interface: 0.00,
 };

 let config = Config {
 min_age_ms: 12.0,
 max_age_ms: 80.0,
 gamma: 2.0,
 epsilon: 0.1,
 critical_confidence: 0.5,
 };

 let tiles = vec![
 Tile {
 name: "Цель у прицела",
 factors: Factors {
 attention: 1.0,
 motion: 0.9,
 input: 0.8,
 target: 1.0,
 saliency: 0.7,
 interface: 0.0,
 },
 confidence: 0.95,
 age_ms: 17.0,
 delta_error: 0.90,
 bytes_kb: 12.0,
 decode_cost: 1.2,
 compose_ms: 0.4,
 },
 Tile {
 name: "Движущийся объект",
 factors: Factors {
 attention: 0.7,
 motion: 0.9,
 input: 0.6,
 target: 0.7,
 saliency: 0.6,
 interface: 0.0,
 },
 confidence: 0.90,
 age_ms: 14.0,
 delta_error: 0.60,
 bytes_kb: 18.0,
 decode_cost: 1.0,
 compose_ms: 0.5,
 },
 Tile {
 name: "Стена на краю",
 factors: Factors {
 attention: 0.1,
 motion: 0.0,
 input: 0.0,
 target: 0.0,
 saliency: 0.2,
 interface: 0.0,
 },
 confidence: 1.0,
 age_ms: 40.0,
 delta_error: 0.15,
 bytes_kb: 30.0,
 decode_cost: 0.8,
 compose_ms: 0.6,
 },
 Tile {
 name: "Непредсказуемая вспышка",
 factors: Factors {
 attention: 0.8,
 motion: 1.0,
 input: 0.7,
 target: 0.9,
 saliency: 1.0,
 interface: 0.0,
 },
 confidence: 0.40,
 age_ms: 10.0,
 delta_error: 0.80,
 bytes_kb: 16.0,
 decode_cost: 1.5,
 compose_ms: 0.5,
 },
 ];

 let mut evaluated: Vec<EvaluatedTile> = tiles
 .iter()
 .enumerate()
 .map(|(index, tile)| {
 evaluate_tile(index, tile, weights, config)
 })
 .collect();

 evaluated.sort_by(|a, b| {
 b.score
 .partial_cmp(&a.score)
 .unwrap_or(Ordering::Equal)
 });

 println!("Оценка тайлов:");

 for item in &evaluated {
 let tile = &tiles[item.index];

 println!(
 "{:25} P={:.3}, age={:.2}, limit={:.2}, \
 slack={:.2}, score={:.6}, forced={}",
 tile.name,
 item.priority,
 tile.age_ms,
 item.age_limit_ms,
 item.slack_ms,
 item.score,
 item.forced
 );
 }

 // Ресурсы на один цикл планирования.
 let mut network_left = 50.0;
 let mut decode_left = 4.5;
 let mut compose_left = 1.8;

 let mut selected = vec![false; tiles.len()];

 // Сначала резервируем ресурсы для обязательных коррекций.
 for item in evaluated.iter().filter(|item| item.forced) {
 let tile = &tiles[item.index];

 if try_reserve(
 tile,
 &mut network_left,
 &mut decode_left,
 &mut compose_left,
 ) {
 selected[item.index] = true;
 } else {
 eprintln!(
 "Не хватает ресурсов для критического тайла: {}",
 tile.name
 );
 }
 }

 // Затем добавляем обычные тайлы по убыванию оценки.
 for item in evaluated.iter().filter(|item| !item.forced) {
 let tile = &tiles[item.index];

 if try_reserve(
 tile,
 &mut network_left,
 &mut decode_left,
 &mut compose_left,
 ) {
 selected[item.index] = true;
 }
 }

 println!("\nВыбранные обновления:");

 for (index, tile) in tiles.iter().enumerate() {
 if selected[index] {
 println!("- {}", tile.name);
 }
 }

 println!(
 "\nОстаток ресурсов: сеть {:.1} КБ, \
 декодер {:.1}, композиция {:.1} мс",
 network_left,
 decode_left,
 compose_left
 );
}
